pub fn sys_exit(exit_code: i32) -> ! {
    trace!("[sys_exit] called with exit_code={}", exit_code);
    exit_current_and_run_next(exit_code);
    panic!("Unreachable in sys_exit!");
}

pub fn sys_exit_group(exit_code: i32) -> SyscallRet {
    trace!("[sys_exit_group] called with exit_code={}", exit_code);
    //exit_current_group_and_run_next(exit_code);
    exit_current_and_run_next(exit_code);
    unreachable!();
}

pub fn sys_set_robust_list(head: usize, len: usize) -> SyscallRet {
    trace!(
        "[sys_set_robust_list] called with head={:#x}, len={}",
        head,
        len
    );
    if len != crate::task::RobustList::HEAD_SIZE {
        return Err(SysErrNo::EINVAL);
    }
    let task = current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    task_inner.robust_list.head = head;
    //inner.robust_list.len = len;
    Ok(0)
}

pub fn sys_settidaddr(tidptr: *mut usize) -> SyscallRet {
    trace!(
        "[sys_settidaddr] called with tidptr=0x{:x} (pointer to store tid for cleanup)",
        tidptr as usize
    );
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    inner.clear_child_tid = Some(tidptr as usize);
    sys_gettid()
}

