pub fn sys_getppid() -> SyscallRet {
    trace!("[sys_getppid] called");
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let parent = inner.parent.as_ref().ok_or(SysErrNo::ESRCH)?;
    Ok(parent.upgrade().unwrap().pid.0)
}

