pub fn sys_clone(flags: usize, stack: usize, ptid: usize, tls: usize, ctid: usize) -> SyscallRet {
    let flags = CloneFlags::from_bits(flags as u32).ok_or_else(|| {
        warn!("Invalid clone flags: {:#x}", flags);
        SysErrNo::EINVAL
    })?;
    trace!(
        "[sys_clone] called with flags={:?} (bits={:#x}), stack={:#x}, ptid={:#x}, tls={:#x}, ctid={:#x}",
        flags, flags.bits(), stack, ptid, tls, ctid
    );
    let current_task = current_task().unwrap();

    let new_task = current_task.clone_task(flags, stack, ptid, tls, ctid);
    info!("new task create end");
    let new_pid = new_task.pid.0;
    add_task(new_task);
    debug!("new pid:{}", new_pid);
    Ok(new_pid)
}

pub fn sys_exec(path: *const u8, mut args: *const usize, mut envp: *const usize) -> SyscallRet {
    trace!(
        "[sys_exec] called with path={:p}, args={:p}, envp={:p}",
        path,
        args,
        envp
    );
    let token = current_user_token();
    let mut path = translated_str(token, path);
    debug!("[sys_exec] resolved path: {}", path);
    let mut env = Vec::<String>::new();
    loop {
        if envp.is_null() {
            break;
        }
        let envp_ptr = *translated_ref(token, envp);
        if envp_ptr == 0 {
            break;
        }
        env.push(translated_str(token, envp_ptr as *const u8));
        unsafe {
            envp = envp.add(1);
        }
    }

    env.push("PATH=/:/bin:".to_string());
    env.push("LD_LIBRARY_PATH=/:/lib:/usr/lib:".to_string());

    let mut args_vec: Vec<String> = Vec::new();

    loop {
        // trace!("task::process::sys_exec");
        if args.is_null() {
            break;
        }
        let arg_str_ptr = *translated_ref(token, args);
        if arg_str_ptr == 0 {
            break;
        }
        debug!("str：{}", translated_str(token, arg_str_ptr as *const u8));
        args_vec.push(translated_str(token, arg_str_ptr as *const u8));

        unsafe {
            args = args.add(1);
        }
    }
    if path.ends_with(".sh") {
        //.sh文件不是可执行文件，需要用busybox的sh来启动
        args_vec.insert(0, String::from("sh"));
        args_vec.insert(0, String::from("busybox"));
        path = String::from("/musl/busybox");
    }
    let task = current_task().unwrap();
    let abs_path = get_abs_path(
        task.inner_exclusive_access().fsinfo.get_cwd().as_str(),
        path.as_str(),
    );
    let app_inode = open(abs_path.as_str(), OpenFlags::O_RDONLY)?.file()?;
    let all_data = app_inode.inode.read_all().unwrap();
    let argc = args_vec.len();
    task.exec(all_data.as_slice(), &args_vec, &mut env);
    debug!("arg num:{}", argc);
    Ok(0)
}

pub fn sys_wait4(pid: isize, status_ptr: *mut i32, option: isize) -> SyscallRet {
    trace!(
        "[sys_wait4] Enter: pid={}, status_ptr=0x{:x} (output pointer for exit status), option={}",
        pid,
        status_ptr as usize,
        option
    );
    // now we only finish option 0 and option 1

    loop {
        let task = current_task().unwrap();
        let mut inner = task.inner_exclusive_access();
        if !inner
            .children
            .iter()
            .any(|p| pid == -1 || pid as usize == p.getpid())
        {
            info!("[sys_wait4] current task pid: {}", task.pid.0);
            warn!("[sys_wait4] No child process found with pid={}", pid);
            return Err(SysErrNo::ECHILD);
            // ---- release current PCB
        }
        let pair = inner.children.iter().enumerate().find(|(_, p)| {
            // ++++ temporarily access child PCB exclusively
            p.inner_exclusive_access().is_zombie() && (pid == -1 || pid as usize == p.getpid())
            // ++++ release child PCB
        });
        if let Some((idx, _)) = pair {
            let child = inner.children.remove(idx);
            // confirm that child will be deallocated after being removed from children list
            assert_eq!(Arc::strong_count(&child), 1);
            let found_pid = child.getpid();
            // ++++ temporarily access child PCB exclusively
            // println!{
            //     "Process {} exit with exit_code {} ...\n",
            //     found_pid, childinner.exit_code
            // };
            let exit_code = child.inner_exclusive_access().exit_code;
            let time_data = &child.inner_exclusive_access().time_data;
            inner.time_data.add_child_time(time_data);
            // ++++ release child PCB
            if !status_ptr.is_null() {
                //退出状态存储在 status 的高 8 位中
                let status = exit_code << 8; // 将退出状态编码到高 8 位

                // *translated_refmut(inner.memory_set.token(), status_ptr) = status;
                put_data(inner.memory_set.token(), status_ptr, status);
            }
            return Ok(found_pid);
        } else {
            // If WNOHANG is specified, return 0 if no child has exited
            if option & 0x01 != 0 {
                return Ok(0);
            }
            // 未找到匹配子进程且未设置 `WNOHANG`，需要阻塞等待
            drop(inner);
            drop(task);
            suspend_current_and_run_next();
        }
    }
}

