pub struct MemorySetInner {
    pub page_table: Arc<PageTableWrapper>,
    pub areas: Vec<MapArea>,
}

impl MemorySetInner {
    ///Create an empty `MemorySetInner`
    pub fn new_bare() -> Self {
        Self {
            page_table: Arc::new(PageTableWrapper::alloc()),
            areas: Vec::new(),
        }
    }

    ///Get pagetable `root_ppn`
    pub fn token(&self) -> PageTable {
        self.page_table.0
    }
    pub fn lazy_page_fault(&mut self, vaddr: VirtAddr, trap_type: TrapType) -> bool {
        if let Some((paddr, map_flags)) = self.translate(vaddr) {
            warn!("[lazy_page_fault] vaddr, paddr:{:#x}", paddr.raw());
            return false;
        }
        if let Some(area) = self
            .areas
            .iter_mut()
            .filter(|area| area.area_type == MapAreaType::Mmap)
            .find(|area| {
                let (start, end) = area.vaddr_range.range();
                start <= vaddr && vaddr < end
            })
        {
            match trap_type {
                TrapType::LoadPageFault(_) => {
                    mmap_read_page_fault(vaddr.into(), &mut self.page_table, area);
                }
                TrapType::StorePageFault(_) => {
                    mmap_write_page_fault(vaddr.into(), &mut self.page_table, area);
                }
                _ => {
                    warn!("unexpected trap_type: {:?}", trap_type);
                    return false;
                }
            }
            return true;
        }
        if let Some(area) = self
            .areas
            .iter_mut()
            .filter(|area| {
                area.area_type == MapAreaType::Brk || area.area_type == MapAreaType::Stack
            })
            .find(|area| {
                let (start, end) = area.vaddr_range.range();
                start <= vaddr && vaddr < end
            })
        {
            area.map_one(&self.page_table, vaddr);
            true
        } else {
            false
        }
    }
    pub fn cow_page_fault(&mut self, vaddr: VirtAddr, trap_type: TrapType) -> bool {
        match trap_type {
            TrapType::LoadPageFault(_) => {
                warn!(
                    "cow page fault only for store page fault, trap_type: {:?}",
                    trap_type
                );
                return false;
            }
            _ => {}
        }
        let flags = self.if_vaddr_cow(vaddr);
        // debug!(
        //     "[cow_page_fault] vaddr: {:#x}, flags: {:?}",
        //     vaddr.raw(),
        //     flags
        // );
        //找到触发cow的段
        if let Some(area) = self
            .areas
            .iter_mut()
            .filter(|area| {
                area.area_type == MapAreaType::Elf
                    || area.area_type == MapAreaType::Brk
                    || area.area_type == MapAreaType::Mmap
            })
            .find(|area| {
                let (start, end) = area.vaddr_range.range();
                start <= vaddr && vaddr < end
            })
        {
            if let Some(flags) = flags {
                cow_page_fault(vaddr.into(), flags, &self.page_table, area);
                return true;
            }
        }
        false
    }
    pub fn push(&mut self, mut map_area: MapArea, offset: usize, data: Option<&[u8]>) {
        map_area.map(&self.page_table);
        if let Some(data) = data {
            map_area.copy_data(&self.page_table, offset, data);
        }
        self.areas.push(map_area);
    }
    fn push_with_given_frames(&mut self, mut map_area: MapArea, frames: Vec<Arc<FrameTracker>>) {
        map_area.map_given_frames(&mut self.page_table, frames);
        self.areas.push(map_area);
    }

    pub fn push_lazily(&mut self, map_area: MapArea) {
        self.areas.push(map_area);
    }

    pub fn mmap(
        &mut self,
        addr: usize,
        len: usize,
        map_perm: MapPermission,
        flags: MmapFlags,
        file: Option<Arc<OSInode>>,
        off: usize,
    ) -> usize {
        if flags.contains(MmapFlags::MAP_FIXED) {
            let start_vaddr = VirtAddr::from(addr).floor();
            let end_vaddr = VirtAddr::from(addr + len).ceil();
            let need_split = self.areas.iter().any(|area| {
                let (l, r) = area.vaddr_range.range();
                if l <= start_vaddr && end_vaddr <= r {
                    !(l == start_vaddr && r == end_vaddr && map_perm == area.map_perm)
                } else {
                    false
                }
            });
            if need_split {
                self.mprotect(start_vaddr, end_vaddr, map_perm);
            } else {
                self.push_lazily(MapArea::new_mmap(
                    VirtAddr::from(addr),
                    VirtAddr::from(addr + len),
                    MapType::Framed,
                    map_perm,
                    MapAreaType::Mmap,
                    file,
                    off,
                    flags,
                ));
            }
            return addr;
        }
        let addr = self.find_insert_addr(MMAP_TOP, len);
        debug!(
            "[mmap] start_va:{:#x},end_va:{:#x}",
            VirtAddr::from(addr).raw(),
            VirtAddr::from(addr + len).raw()
        );
        self.push_lazily(MapArea::new_mmap(
            VirtAddr::from(addr),
            VirtAddr::from(addr + len),
            MapType::Framed,
            map_perm,
            MapAreaType::Mmap,
            file,
            off,
            flags,
        ));
        addr
    }

    pub fn munmap(&mut self, addr: VirtAddr, len: usize) -> SyscallRet {
        let start_vaddr = addr.floor();
        if len == 0 {
            return Ok(0);
        }
        let end_vaddr = (addr + len).ceil();
        // 拆出需要解除的区段（只返回重叠部分，不再放回）
        let overlapping = self.split_area_by_range(start_vaddr, end_vaddr);
        if overlapping.is_empty() {
            return Ok(0);
        }
        for mut area in overlapping {
            // area 不再回插，Drop 自动处理 group
            let is_file_shared = area.area_type == MapAreaType::Mmap
                && area.mmap_file.file.is_some()
                && area.mmap_flags.contains(MmapFlags::MAP_SHARED);
            if is_file_shared {
                let file = area.mmap_file.file.as_ref().unwrap();
                // 收集已触碰页并按地址排序
                let mut vaddrs: Vec<_> = area
                    .data_frames
                    .keys()
                    .filter(|vaddr| self.translate((**vaddr).into()).is_some())
                    .cloned()
                    .collect();
                vaddrs.sort_by_key(|vaddr| vaddr.raw());

                // 合并相邻页面成连续范围
                let mut write_ranges = Vec::new();
                let mut current_start = None;
                let mut current_end = None;

                for vaddr in vaddrs {
                    if current_start.is_none() {
                        current_start = Some(vaddr);
                        current_end = Some(VirtAddr::from(vaddr.raw() + PAGE_SIZE));
                    } else if vaddr.raw() == current_end.unwrap().raw() {
                        // 相邻页面，扩展范围
                        current_end = Some(VirtAddr::from(vaddr.raw() + PAGE_SIZE));
                    } else {
                        // 不相邻，保存当前范围，开始新范围
                        write_ranges.push((current_start.unwrap(), current_end.unwrap()));
                        current_start = Some(vaddr);
                        current_end = Some(VirtAddr::from(vaddr.raw() + PAGE_SIZE));
                    }
                }

                if let (Some(start), Some(end)) = (current_start, current_end) {
                    write_ranges.push((start, end));
                }

                // 按范围批量写回
                for (start_vaddr, end_vaddr) in write_ranges {
                    let file_off = area.mmap_file.offset
                        + (start_vaddr.raw() - area.vaddr_range.get_start().raw());
                    let size = end_vaddr.raw() - start_vaddr.raw();

                    let _ = file.lseek(file_off as isize, SEEK_SET);
                    file.write(UserBuffer {
                        buffers: translated_byte_buffer(
                            &self.page_table,
                            start_vaddr.raw() as *mut u8,
                            size,
                        ),
                    });
                }
            }
            // 解除映射（仅对存在的帧）
            let vaddrs: Vec<_> = area.data_frames.keys().cloned().collect();
            for vaddr in vaddrs {
                area.unmap_one(&self.page_table, vaddr);
            }
        }
        TLB::flush_all();
        Ok(0)
    }

    pub fn remove_area(&mut self, start_vaddr: VirtAddr) {
        // 找到匹配的 MapArea
        if let Some(index) = self
            .areas
            .iter()
            .position(|area| area.vaddr_range.get_start() == start_vaddr)
        {
            let mut area = self.areas.remove(index);
            // 取消映射该区域
            area.unmap(&self.page_table);
        } else {
            warn!(
                "Attempted to remove a non-existent area with start_vaddr: {:?}",
                start_vaddr
            );
        }
    }

    pub fn find_free_area(&self, size: usize) -> usize {
        let mut current_addr = usize::from(VirtAddr::from(self.areas[0].vaddr_range.get_start())); // 假设从用户地址空间的基地址开始
        for area in &self.areas {
            debug!(
                "[find_free_area] Checking current_addr: 0x{:x}",
                current_addr
            );
            if current_addr + size <= usize::from(VirtAddr::from(area.vaddr_range.get_start())) {
                return current_addr;
            }
            current_addr = usize::from(VirtAddr::from(area.vaddr_range.get_end()));
        }
        current_addr // 返回找到的空闲地址
    }
    /// Include sections in elf and trampoline and TrapContext and user stack,
    /// also returns user_sp and entry point.
    pub fn from_elf(elf_data: &[u8]) -> (Self, usize, usize, Vec<Aux>) {
        let mut memory_set = Self::new_bare();
        let mut auxv = Vec::new();
        // map program headers of elf, with U flag
        let elf = xmas_elf::ElfFile::new(elf_data).unwrap();
        let elf_header = elf.header;
        let magic = elf_header.pt1.magic;
        assert_eq!(magic, [0x7f, 0x45, 0x4c, 0x46], "invalid elf!");
        let ph_count = elf_header.pt2.ph_count();
        let mut entry_point = elf.header.pt2.entry_point() as usize;
        auxv.push(Aux::new(
            AuxType::PHENT,
            elf.header.pt2.ph_entry_size() as usize,
        )); // ELF64 header 64bytes
        auxv.push(Aux::new(AuxType::ENTRY, entry_point));
        auxv.push(Aux::new(AuxType::PAGESZ, PAGE_SIZE as usize));
        if let Some(interp_entry_point) = memory_set.load_dl_interp_if_needed(&elf) {
            info!(
                "[from_elf] Loaded dynamic linker interpreter at entry point: {:#x}",
                interp_entry_point
            );
            auxv.push(Aux::new(AuxType::BASE, DL_INTERP_OFFSET));
            entry_point = interp_entry_point;
        } else {
            auxv.push(Aux::new(AuxType::BASE, 0));
        }
        auxv.push(Aux::new(AuxType::UID, 0 as usize));
        auxv.push(Aux::new(AuxType::EUID, 0 as usize));
        auxv.push(Aux::new(AuxType::GID, 0 as usize));
        auxv.push(Aux::new(AuxType::PHNUM, ph_count as usize));
        auxv.push(Aux::new(AuxType::EGID, 0 as usize));
        auxv.push(Aux::new(AuxType::PLATFORM, 0 as usize));
        auxv.push(Aux::new(AuxType::HWCAP, 0 as usize));
        auxv.push(Aux::new(AuxType::CLKTCK, 100 as usize));
        auxv.push(Aux::new(AuxType::SECURE, 0 as usize));
        auxv.push(Aux::new(AuxType::NOTELF, 0x112d as usize));

        let mut max_end_va = VirtAddr::new(0);
        let mut head_va = 0;
        let mut lcsh = false;
        for i in 0..ph_count {
            let ph = elf.program_header(i).unwrap();
            if ph.get_type().unwrap() == xmas_elf::program::Type::Load {
                let start_va: VirtAddr = (ph.virtual_addr() as usize).into();
                if !lcsh {
                    lcsh = true;
                    head_va = start_va.raw();
                }
                let end_va: VirtAddr = ((ph.virtual_addr() + ph.mem_size()) as usize).into();
                let mut map_perm = MapPermission::U;
                let ph_flags = ph.flags();
                if ph_flags.is_read() {
                    map_perm |= MapPermission::R;
                }
                if ph_flags.is_write() {
                    map_perm |= MapPermission::W;
                }
                if ph_flags.is_execute() {
                    map_perm |= MapPermission::X;
                }
                let map_area = MapArea::new(
                    start_va,
                    end_va,
                    MapType::Framed,
                    map_perm,
                    MapAreaType::Elf,
                );
                let offset = start_va.raw() - start_va.floor().raw();
                if end_va > max_end_va {
                    max_end_va = end_va;
                }
                let data_slice =
                    &elf.input[ph.offset() as usize..(ph.offset() + ph.file_size()) as usize];
                // 打印数据的前16字节用于调试
                let offset1 = 0x1634c8 - 0x162ff0; // 0x24c8
                let offset2 = 0x1634d0 - 0x162ff0; // 0x24d0

                memory_set.push(
                    map_area,
                    offset,
                    Some(&elf.input[ph.offset() as usize..(ph.offset() + ph.file_size()) as usize]),
                );
                info!("map area from {:#x} to {:#x}", start_va.raw(), end_va.raw());
            }
        }
        let ph_head_addr = head_va + elf.header.pt2.ph_offset() as usize;
        auxv.push(Aux {
            aux_type: AuxType::PHDR,
            value: ph_head_addr as usize,
        });

        let mut user_heap_bottom = max_end_va.ceil();
        user_heap_bottom = user_heap_bottom + PAGE_SIZE;
        let user_heap_top = user_heap_bottom;
        memory_set.push_lazily(MapArea::new(
            user_heap_bottom,
            user_heap_top,
            MapType::Framed,
            MapPermission::R | MapPermission::W | MapPermission::U,
            MapAreaType::Brk,
        ));
        (
            memory_set,
            // user_stack_top.into(),
            user_heap_bottom.into(),
            entry_point,
            auxv,
        )
    }
    fn map_elf(&mut self, elf: &ElfFile, offset: VirtAddr) -> (VirtAddr, VirtAddr) {
        let elf_header = elf.header;
        let ph_count = elf_header.pt2.ph_count();

        let mut max_end_vpn = offset.floor();
        let mut header_va = 0;
        let mut has_found_header_va = false;

        for i in 0..ph_count {
            let ph = elf.program_header(i).unwrap();
            if ph.get_type().unwrap() == xmas_elf::program::Type::Load {
                let start_va: VirtAddr = (ph.virtual_addr() as usize + offset.raw()).into();
                let end_va: VirtAddr =
                    ((ph.virtual_addr() + ph.mem_size()) as usize + offset.raw()).into();
                if !has_found_header_va {
                    header_va = start_va.raw();
                    has_found_header_va = true;
                }
                let mut map_perm = MapPermission::U;
                let ph_flags = ph.flags();
                if ph_flags.is_read() {
                    map_perm |= MapPermission::R;
                }
                if ph_flags.is_write() {
                    map_perm |= MapPermission::W;
                }
                if ph_flags.is_execute() {
                    map_perm |= MapPermission::X;
                }
                let map_area = MapArea::new(
                    start_va,
                    end_va,
                    MapType::Framed,
                    map_perm,
                    MapAreaType::Elf,
                );
                let data_offset = start_va.raw() - start_va.floor().raw();
                max_end_vpn = map_area.vaddr_range.get_end();
                self.push(
                    map_area,
                    data_offset,
                    Some(&elf.input[ph.offset() as usize..(ph.offset() + ph.file_size()) as usize]),
                );
            }
        }
        (max_end_vpn, header_va.into())
    }
    pub fn from_existed_user(user_space: &MemorySetInner) -> MemorySetInner {
        trace!("[from_existed_user]");
        let mut memory_set = Self::new_bare();
        // copy data sections/trap_context/user_stack
        for area in user_space.areas.iter() {
            let mut new_area = MapArea::from_another(area);
            // 根据区域类型选择不同的复制策略
            // 栈（Stack）和堆（Brk）区域都是懒加载的，因此只复制已经映射的物理页
            if area.area_type == MapAreaType::Stack {
                trace!("[from_existed_user]: Stack area");
                // 对于懒加载区域，新的内存空间也应该是懒加载的
                memory_set.push_lazily(new_area);
                // 从高地址到低地址遍历，只复制已经存在的页面
                for vaddr in area.vaddr_range.into_iter().rev() {
                    // 检查源页面是否存在映射
                    if let Some((src_paddr, _)) = user_space.translate(vaddr) {
                        debug!(
                            "[from_existed_user] copy data from src_paddr: {:#x},vpn: {:#x}",
                            src_paddr.raw(),
                            vaddr.raw()
                        );
                        // 源页面存在，为目标页面分配物理帧并建立映射
                        let dst_area = memory_set
                            .areas
                            .iter_mut()
                            .find(|a| a.vaddr_range.range() == area.vaddr_range.range())
                            .unwrap();
                        dst_area.map_one(&memory_set.page_table, vaddr);
                        // 获取目标页面的物理地址
                        let dst_paddr = memory_set.translate(vaddr).unwrap().0;
                        // 复制数据
                        unsafe {
                            core::ptr::copy_nonoverlapping(
                                src_paddr.get_ptr::<u8>(),
                                dst_paddr.get_mut_ptr(),
                                PAGE_SIZE,
                            );
                        }
                    }
                }
            } else if area.area_type == MapAreaType::Brk || area.area_type == MapAreaType::Mmap {
                new_area.data_frames = area.data_frames.clone();
                for (vaddr, _) in area.data_frames.iter() {
                    let (paddr, flags) = user_space.translate(*vaddr).unwrap();
                    let mut new_flags = (flags & !MappingFlags::W);
                    if flags.contains(MappingFlags::COW) || flags.contains(MappingFlags::W) {
                        new_flags = new_flags | MappingFlags::COW;
                    }
                    user_space.page_table.update_page_flags(*vaddr, new_flags);
                    memory_set
                        .page_table
                        .map_page(*vaddr, paddr, new_flags, MappingSize::Page4KB);
                }
                memory_set.push_lazily(new_area);
                continue;
            } else if area.area_type == MapAreaType::Elf {
                for vaddr in area.vaddr_range {
                    let (paddr, flags) = user_space.translate(vaddr).unwrap();
                    let mut new_flags = (flags & !MappingFlags::W) | MappingFlags::COW;
                    user_space.page_table.update_page_flags(vaddr, new_flags);
                    memory_set
                        .page_table
                        .map_page(vaddr, paddr, new_flags, MappingSize::Page4KB);
                }
                new_area.data_frames = area.data_frames.clone();
                memory_set.push_lazily(new_area);
                continue;
            } else {
                debug!(
                    "[from_existed_user] other area_type: {:?}, vaddr_range: {:#x} - {:#x}",
                    area.area_type,
                    area.vaddr_range.get_start().raw(),
                    area.vaddr_range.get_end().raw()
                );
                // 对于其他区域（如代码段、数据段），它们是预先完全映射的，使用原有策略
                memory_set.push(new_area, 0, None);
                // 复制数据
                for vaddr in area.vaddr_range {
                    // if let Some((_, _)) = user_space.translate(vaddr) {
                    // } else {
                    //     debug!(
                    //         "[from_existed_user] vaddr {:#x} ,
                    //         area.vaddr_range: {:#x} - {:#x},
                    //         area_type: {:?}",
                    //         vaddr.raw(),
                    //         area.vaddr_range.get_start().raw(),
                    //         area.vaddr_range.get_end().raw(),
                    //         area.area_type
                    //     );
                    //     continue;
                    // }
                    let src = user_space.translate(vaddr).unwrap().0;
                    let dst = memory_set.translate(vaddr).unwrap().0;
                    unsafe {
                        core::ptr::copy_nonoverlapping(
                            src.get_ptr::<u8>(),
                            dst.get_mut_ptr(),
                            PAGE_SIZE,
                        );
                    }
                }
            }
        }
        info!(
            "[from_existed_user]: memory_set created with {} areas",
            memory_set.areas.len()
        );
        memory_set
    }
