pub fn lazy_insert_framed_area_with_hint(
        &mut self,
        hint: usize,
        size: usize,
        map_perm: MapPermission,
        area_type: MapAreaType,
    ) -> (usize, usize) {
        trace!(
            "[lazy_insert_framed_area_with_hint], hint: {:#x}, size: {:#x}",
            hint,
            size
        );
        let start_va = self.find_insert_addr(hint, size);
        let end_va = start_va + size;
        self.lazy_insert_framed_area(
            VirtAddr::from(start_va),
            VirtAddr::from(end_va),
            map_perm,
            area_type,
        );
        (start_va, end_va)
    }

pub fn find_insert_addr(&self, mut hint: usize, size: usize) -> usize {
        loop {
            let end_vaddr = VirtAddr::from(hint).floor();
            let start_vaddr = VirtAddr::from(hint - size).floor();
            let mut conflict = false;
            for area in self.areas.iter() {
                let (start, end) = area.vaddr_range.range();
                if end_vaddr > start && start_vaddr < end {
                    // 有冲突，调整 hint，继续循环
                    hint = VirtAddr::from(start_vaddr).raw() - PAGE_SIZE;
                    conflict = true;
                    break;
                }
            }
            if !conflict {
                debug!(
                    "[find_insert_addr] found addr: {:#x} - {:#x}",
                    start_vaddr.raw(),
                    end_vaddr.raw()
                );
                return VirtAddr::from(start_vaddr).raw();
            }
        }
    }

pub fn lazy_insert_framed_area(
        &mut self,
        start_va: VirtAddr,
        end_va: VirtAddr,
        permission: MapPermission,
        area_type: MapAreaType,
    ) {
        self.push_lazily(MapArea::new(
            start_va,
            end_va,
            MapType::Framed,
            permission,
            area_type,
        ));
    }

fn load_dl_interp_if_needed(&mut self, elf: &ElfFile) -> Option<usize> {
        let elf_header = elf.header;
        let ph_count = elf_header.pt2.ph_count();

        // 1. 检查是否有 PT_INTERP 段
        let mut has_interp = false;
        for i in 0..ph_count {
            let ph = elf.program_header(i).unwrap();
            if ph.get_type().unwrap() == xmas_elf::program::Type::Interp {
                has_interp = true;
                break;
            }
        }

        // 2. 检查 .dynamic 节是否有 DT_NEEDED 条目
        let mut has_needed = false;
        if let Some(dynamic_section) = elf.find_section_by_name(".dynamic") {
            let data = dynamic_section.raw_data(elf);
            let entry_size = 16;
            let count = data.len() / entry_size;
            for i in 0..count {
                let offset = i * entry_size;
                // d_tag: u64 at offset 0
                let d_tag = u64::from_le_bytes([
                    data[offset],
                    data[offset + 1],
                    data[offset + 2],
                    data[offset + 3],
                    data[offset + 4],
                    data[offset + 5],
                    data[offset + 6],
                    data[offset + 7],
                ]);
                if d_tag == 1 {
                    has_needed = true;
                    break;
                }
            }
        }

        if has_interp && has_needed {
            debug!("[load_dl] encounter a real dynamic linked elf");
            let section = elf.find_section_by_name(".interp").unwrap();
            let mut interp = String::from_utf8(section.raw_data(&elf).to_vec()).unwrap();
            interp = interp.strip_suffix("\0").unwrap_or(&interp).to_string();
            debug!("[load_dl] interp {}", interp);

            let mut interps: Vec<String> = vec![interp.clone()];

            debug!("interp {}", interp);

            if interp.eq("/lib/ld-musl-riscv64-sf.so.1")
                || interp.eq("/lib/ld-musl-riscv64.so.1")
                || interp.eq("/lib64/ld-musl-loongarch-lp64d.so.1")
                || interp.eq("/lib64ld-linux-loongarch-lp64d.so.1")
            {
                interps.insert(0, "ld-musl-riscv64.so.1".to_string());
            }
            if interp.eq("/lib/ld-glibc-riscv64-sf.so.1")
                || interp.eq("/lib/ld-glibc-riscv64.so.1")
                || interp.eq("/lib64/ld-glibc-loongarch64-sf.so.1")
                || interp.eq("/lib64/ld-linux-loongarch-lp64d.so.1")
            {
                interps.insert(0, "/glibc/lib/libc.so.6".to_string());
            }

            let mut interp_inode = None;
            for interp in interps {
                if let Ok(inode) = open(&interp, OpenFlags::O_RDONLY) {
                    debug!("read interp from {}", &interp);
                    interp_inode = inode.file().ok();
                    break;
                }
            }
            let interp_file = interp_inode.unwrap();
            let interp_elf_data = interp_file.inode.read_all().unwrap();
            let interp_elf = xmas_elf::ElfFile::new(&interp_elf_data).unwrap();
            self.map_elf(&interp_elf, DL_INTERP_OFFSET.into());

            Some(interp_elf.header.pt2.entry_point() as usize + DL_INTERP_OFFSET)
        } else {
            debug!("[load_dl] static or pseudo-dynamic elf (no DT_NEEDED)");
            None
        }
    }

