pub fn split_area_by_range(
        &mut self,
        start_addr: VirtAddr,
        end_addr: VirtAddr,
    ) -> Vec<MapArea> {
        let mut new_areas_to_add = Vec::new();
        let mut overlapping = Vec::new();

        // 1. 收集完全被包含的区域
        let mut starts = Vec::new();
        for area in self.areas.iter() {
            let (start, end) = area.vaddr_range.range();
            if start >= start_addr && end <= end_addr {
                starts.push(start);
            }
        }
        // 2. 移除这些区域并放入 overlapping
        self.areas.retain(|area| {
            if starts.contains(&area.vaddr_range.get_start()) {
                overlapping.push(area.clone());
                false
            } else {
                true
            }
        });

        // 3. 处理部分重叠的区域（拆分）
        for area in self.areas.iter_mut() {
            let (start, end) = area.vaddr_range.range();
            if end <= start_addr || start >= end_addr {
                continue;
            }
            let is_file_mmap = area.area_type == MapAreaType::Mmap && area.mmap_file.file.is_some();
            let old_start = start; // 保存旧起点
            let old_offset = area.mmap_file.offset; // 保存旧 offset

            // Case A: 尾部重叠  [area.....)
            //                          [target...)
            if start < start_addr && end > start_addr && end <= end_addr {
                let mut overlapping_part = MapArea::from_another(area);
                // 原区域缩成前半段，起点不变 -> offset 不变
                area.vaddr_range = VAddrRange::new(start, start_addr);
                // 重叠段起点 = start_addr
                overlapping_part.vaddr_range = VAddrRange::new(start_addr, end);
                if is_file_mmap {
                    let delta = start_addr.raw() - old_start.raw();
                    overlapping_part.mmap_file.offset = old_offset + delta;
                }
                // 迁移帧
                let mut frames_to_move = BTreeMap::new();
                area.data_frames.retain(|va, frame| {
                    if *va >= start_addr {
                        frames_to_move.insert(*va, frame.clone());
                        false
                    } else {
                        true
                    }
                });
                overlapping_part.data_frames = frames_to_move;
                overlapping.push(overlapping_part);
            // Case B: 头部重叠        [area.....)
            //                 [target...) 剩余后半
            } else if start >= start_addr && start < end_addr && end > end_addr {
                let mut overlapping_part = MapArea::from_another(area);
                // 重叠段 = 原起点到 end_addr
                overlapping_part.vaddr_range = VAddrRange::new(start, end_addr);
                // 原区域改成后半段，起点变为 end_addr，需要调整 offset
                area.vaddr_range = VAddrRange::new(end_addr, end);
                if is_file_mmap {
                    // 原区域起点前移到后半段新起点，offset += (new_start - old_start)
                    let new_start = area.vaddr_range.get_start();
                    let delta_new = new_start.raw() - old_start.raw();
                    area.mmap_file.offset = old_offset + delta_new;
                    // 重叠段起点 = old_start -> offset 仍为 old_offset
                    overlapping_part.mmap_file.offset = old_offset;
                }
                // 迁移帧（属于前半/重叠部分）
                let mut frames_to_move = BTreeMap::new();
                area.data_frames.retain(|va, frame| {
                    if *va < end_addr {
                        frames_to_move.insert(*va, frame.clone());
                        false
                    } else {
                        true
                    }
                });
                overlapping_part.data_frames = frames_to_move;
                overlapping.push(overlapping_part);
            // Case C: 包含 target   [   area (start..end)   ]
            //                      [ target (start_addr..end_addr) ]
            } else if start < start_addr && end > end_addr {
                let mut overlapping_part = MapArea::from_another(area);
                let mut back_part = MapArea::from_another(area);
                // 原区域 -> 前段 [start, start_addr)
                area.vaddr_range = VAddrRange::new(start, start_addr);
                // 中段
                overlapping_part.vaddr_range = VAddrRange::new(start_addr, end_addr);
                // 后段
                back_part.vaddr_range = VAddrRange::new(end_addr, end);
                if is_file_mmap {
                    // 前段起点未变 offset 不动
                    // 中段 offset = old_offset + (start_addr - old_start)
                    let delta_mid = start_addr.raw() - old_start.raw();
                    overlapping_part.mmap_file.offset = old_offset + delta_mid;
                    // 后段 offset = old_offset + (end_addr - old_start)
                    let delta_back = end_addr.raw() - old_start.raw();
                    back_part.mmap_file.offset = old_offset + delta_back;
                }
                // 分帧
                let mut overlapping_frames = BTreeMap::new();
                let mut back_frames = BTreeMap::new();
                area.data_frames.retain(|va, frame| {
                    if *va >= end_addr {
                        back_frames.insert(*va, frame.clone());
                        false
                    } else if *va >= start_addr {
                        overlapping_frames.insert(*va, frame.clone());
                        false
                    } else {
                        true
                    }
                });
                overlapping_part.data_frames = overlapping_frames;
                back_part.data_frames = back_frames;
                overlapping.push(overlapping_part);
                new_areas_to_add.push(back_part);
            }
        }
        // 4. 附加新的非重叠尾段
        self.areas.append(&mut new_areas_to_add);
        overlapping
    }

pub fn mprotect(&mut self, start_addr: VirtAddr, end_addr: VirtAddr, map_perm: MapPermission) {
        let mut overlapping_areas = self.split_area_by_range(start_addr, end_addr);
        for area in overlapping_areas.iter_mut() {
            area.map_perm = map_perm;
            self.areas.push(area.clone());
            for vaddr in area.data_frames.keys() {
                self.page_table.update_page_flags(*vaddr, map_perm.into());
            }
        }
        TLB::flush_all();
    }

pub enum MapType {
    //  Identical, not used now
    Framed,
}

pub fn cow_page_fault(
    vaddr: VirtAddr,
    flags: MappingFlags,
    page_table: &Arc<PageTableWrapper>,
    area: &mut MapArea,
) {
    debug!(
        "[cow_page_fault] vaddr: {:#x}, area: {:?}",
        vaddr.raw(),
        area.vaddr_range
    );
    let frame = area.data_frames.get(&vaddr.into()).unwrap();
    // 如果是唯一的引用，直接将 COW 标志位移除，并添加 W (可写) 标志位
    let new_flags = (flags & !MappingFlags::COW) | MappingFlags::W;
    if Arc::strong_count(frame) == 1 {
        page_table.update_page_flags(vaddr, new_flags);
        return;
    }

    let src_ptr = page_table.translate(vaddr).unwrap().0;
    let src: &mut [u8] =
        unsafe { core::slice::from_raw_parts_mut(src_ptr.get_mut_ptr(), PAGE_SIZE) };
    area.unmap_one(page_table, vaddr);
    area.map_one(page_table, vaddr);
    let dst = &mut page_table
        .translate(vaddr)
        .unwrap()
        .0
        .slice_mut_with_len(PAGE_SIZE);
    dst.copy_from_slice(src);
    page_table.update_page_flags(vaddr, new_flags);
}

pub fn mmap_read_page_fault(va: VirtAddr, page_table: &Arc<PageTableWrapper>, area: &mut MapArea) {
    let frame = GROUP_SHARE.lock().find(area.groupid, va);
    if let Some(frame) = frame {
        let mut flags = area.flags();
        if flags.contains(MappingFlags::W) {
            flags.remove(MappingFlags::W);
            flags.insert(MappingFlags::COW);
        }
        page_table.update_page_flags(va, flags);
        area.data_frames.insert(va, frame);
    } else {
        info!(
            "mmap_read_page_fault: no shared frame found for vaddr: {:#x}",
            va.raw()
        );
        mmap_write_page_fault(va, page_table, area);
        GROUP_SHARE
            .lock()
            .add_frame(area.groupid, va, area.data_frames.get(&va).unwrap().clone());
    }
}

pub fn mmap_write_page_fault(va: VirtAddr, page_table: &Arc<PageTableWrapper>, area: &mut MapArea) {
    area.map_one(page_table, va);
    let file = &area.mmap_file.file;
    if file.is_none() {
        return;
    }
    let file = file.as_ref().unwrap();
    let old_offset = file.lseek(0, SEEK_CUR).unwrap();
    let start = area.vaddr_range.get_start();
    file.lseek(
        (va.raw() - start.raw() + area.mmap_file.offset) as isize,
        SEEK_SET,
    )
    .expect("[mmap_write_page_fault]: lseek failed");
    file.read(UserBuffer {
        buffers: translated_byte_buffer(page_table, va.raw() as *mut u8, PAGE_SIZE),
    });
    let mut flags = area.flags();
    if flags.contains(MappingFlags::W) {
        flags.remove(MappingFlags::W);
        flags.insert(MappingFlags::COW);
    }
    page_table.update_page_flags(va, flags);
}

pub fn sys_shmget(key: i32, size: usize, flags: i32) -> SyscallRet {
    trace!(
        "[sys_shmget] Enter: key=0x{:x}, size={}, flags=0x{:x}",
        key,
        size,
        flags
    );
    const IPC_PRIVATE: i32 = 0;
    // 忽略权限位
    let flags = ShmFlags::from_bits(flags & !0x1ff).unwrap();
    match key {
        IPC_PRIVATE => Ok(shm_create(size)),
        key if key > 0 => {
            if shm_find(key as usize) {
                if flags.contains(ShmFlags::IPC_CREAT | ShmFlags::IPC_EXCL) {
                    Err(SysErrNo::EEXIST)
                } else {
                    Ok(key as usize)
                }
            } else {
                if flags.contains(ShmFlags::IPC_CREAT) {
                    Ok(shm_create(size))
                } else {
                    Err(SysErrNo::ENOENT)
                }
            }
        }
        _ => Err(SysErrNo::ENOENT),
    }
}

pub fn sys_shmctl(shmid: i32, cmd: i32, buf: usize) -> SyscallRet {
    trace!(
        "[sys_shmctl] Enter: shmid={}, cmd={}, buf=0x{:x}",
        shmid,
        cmd,
        buf as usize
    );
    const IPC_RMID: i32 = 0;
    match cmd {
        IPC_RMID => {
            shm_drop(shmid as usize);
            Ok(0)
        }
        _ => {
            panic!("[sys_shmctl] unsupport cmd");
        }
    }
}

pub fn sys_shmat(shmid: i32, shmaddr: usize, shmflag: i32) -> SyscallRet {
    let mut permission = MapPermission::U | MapPermission::R;
    if shmflag == 0 {
        permission |= MapPermission::W | MapPermission::X
    } else {
        let shmflg = ShmFlags::from_bits(shmflag).unwrap();
        if shmflg.contains(ShmFlags::SHM_EXEC) {
            permission |= MapPermission::X;
        }
        if !shmflg.contains(ShmFlags::SHM_RDONLY) {
            permission |= MapPermission::W;
        }
    }

    match shmid {
        key if key < 0 => Err(SysErrNo::EINVAL),
        _ => shm_attach(shmid as usize, shmaddr, permission),
    }
}

pub fn sys_brk(brk_addr: usize) -> SyscallRet {
    trace!("[sys_brk] Enter: brk_addr=0x{:x}", brk_addr);
    // let task = current_task().unwrap();
    // let mut task_inner = task.inner_exclusive_access();
    let current_addr = current_task().unwrap().growproc(0) as usize;
    debug!("[sys_brk] Current heap end: 0x{:x}", current_addr);
    if brk_addr == 0 {
        debug!("[sys_brk] Querying current brk: 0x{:x}", current_addr);
        return Ok(current_addr);
    }
    let grow_size = (brk_addr - current_addr) as isize;
    debug!(
        "[sys_brk] Growing heap by: {} bytes (0x{:x})",
        grow_size, grow_size
    );
    let result = current_task().unwrap().growproc(grow_size) as usize;
    trace!("[sys_brk] return: result=0x{:x}", result);
    Ok(result)
}

pub fn sys_munmap(addr: usize, len: usize) -> SyscallRet {
    trace!("[sys_munmap] Enter: addr=0x{:x}, len=0x{:x}", addr, len);
    let task = current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    let len = page_round_up(len);
    task_inner.memory_set.munmap(VirtAddr::from(addr), len)
}

pub fn sys_mmap(
    start: usize,
    len: usize,
    prot: usize,
    flags: usize,
    fd: usize,
    offset: usize,
) -> SyscallRet {
    trace!("[sys_mmap] Enter: start=0x{:x}, len=0x{:x}, prot=0x{:x}, flags=0x{:x}, fd={}, offset=0x{:x}",
           start, len, prot, flags, fd, offset);
    let mmap_prot = MapPermission::from(MmapProt::from_bits(prot as u32).unwrap());
    let flags = MmapFlags::from_bits(flags as u32).unwrap();
    if flags.contains(MmapFlags::MAP_FIXED) && start == 0 {
        return Err(SysErrNo::EPERM);
    }
    let len = page_round_up(len);
    let task = current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    if fd == usize::MAX {
        if !flags.contains(MmapFlags::MAP_ANONYMOUS) {
            return Err(SysErrNo::EBADF);
        }
        let rv = task_inner
            .memory_set
            .mmap(start, len, mmap_prot, flags, None, offset);
        return Ok(rv);
    }
    debug!("[sys_mmap] Mapping file descriptor: {}", fd);
    if let Some(file) = &task_inner.fd_table.get_file(fd) {
        let file = file.file().unwrap();
        let addr = task_inner
            .memory_set
            .mmap(start, len, mmap_prot, flags, Some(file), offset);
        info!("[sys_mmap] Successfully mapped at: 0x{:x}", addr);
        Ok(addr)
    } else {
        warn!("[sys_mmap] Invalid file descriptor: {}", fd);
        Err(SysErrNo::EPERM)
    }
}

pub fn sys_mprotect(addr: usize, len: usize, prot: u32) -> SyscallRet {
    trace!(
        "[sys_mprotect] Enter: addr=0x{:x}, len=0x{:x}, prot=0x{:x}",
        addr,
        len,
        prot
    );

    if (addr % PAGE_SIZE != 0) || (len % PAGE_SIZE != 0) {
        return Err(SysErrNo::EINVAL);
    } //检查页面对齐

    let map_perm: MapPermission = MmapProt::from_bits(prot).unwrap().into();

    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    let memory_set = &mut inner.memory_set;
    let start_vpn = VirtAddr::from(addr).floor();
    let end_vpn = VirtAddr::from(addr + len).ceil();

    memory_set.mprotect(start_vpn, end_vpn, map_perm);
    Ok(0)
}

pub(crate) struct Feature: u64 {
        // device independent
        const NOTIFY_ON_EMPTY       = 1 << 24; // legacy
        const ANY_LAYOUT            = 1 << 27; // legacy
        const RING_INDIRECT_DESC    = 1 << 28;
        const RING_EVENT_IDX        = 1 << 29;
        const UNUSED                = 1 << 30; // legacy
        const VERSION_1             = 1 << 32; // detect legacy

        // since virtio v1.1
        const ACCESS_PLATFORM       = 1 << 33;
        const RING_PACKED           = 1 << 34;
        const IN_ORDER              = 1 << 35;
        const ORDER_PLATFORM        = 1 << 36;
        const SR_IOV                = 1 << 37;
        const NOTIFICATION_DATA     = 1 << 38;
    }

pub enum MmioVersion {
    /// Legacy MMIO transport with page-based addressing.
    Legacy = LEGACY_VERSION,
    /// Modern MMIO transport.
    Modern = MODERN_VERSION,
}

impl TryFrom<u32> for MmioVersion {
    type Error = MmioError;

    fn try_from(version: u32) -> Result<Self, Self::Error> {
        match version {
            LEGACY_VERSION => Ok(Self::Legacy),
            MODERN_VERSION => Ok(Self::Modern),
            _ => Err(MmioError::UnsupportedVersion(version)),
        }
    }
}

