pub fn sys_unlinkat(dirfd: isize, path: *const u8, flags: u32) -> SyscallRet {
    let flags = UnlinkatFlags::from_bits_truncate(flags);
    trace!(
        "[sys_unlinkat] called with dirfd={}, path={:p}, flags={:?} (bits={:#x})",
        dirfd,
        path,
        flags,
        flags.bits()
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let path_str = translated_str(token, path);
    debug!("[sys_unlinkat] path string: {}", path_str);
    let abs_path = inner.get_abs_path(dirfd, &path_str)?;
    drop(inner);
    drop(task);
    debug!("[sys_unlinkat] absolute path: {}", abs_path);
    let inode = open(abs_path.as_str(), OpenFlags::O_RDONLY)?.file()?;
    let link_cnt = inode.inode.link_cnt().unwrap_or(1);
    if link_cnt == 1 {
        inode.inode.delay();
        remove_inode_idx(&abs_path.as_str());
        info!("[sys_unlinkat] delayed and removed inode for {}", abs_path);
    } else {
        inode.inode.unlink(&abs_path)?;
        remove_inode_idx(&abs_path.as_str());
        info!("[sys_unlinkat] unlinked and removed inode for {}", abs_path);
    }
    Ok(0)
}

