    let old_abs = inner.get_abs_path(oldfd, &oldpath)?;
    let new_abs = inner.get_abs_path(newfd, &newpath)?;
    debug!("[sys_linkat] old_abs: {}, new_abs: {}", old_abs, new_abs);
    drop(inner);
    drop(task);
    // 检查 old_abs 是否存在
    let src_inode = open(&old_abs, OpenFlags::O_RDONLY)?.file()?;

    // 检查 new_abs 的父目录是否存在
    let new_parent = match new_abs.rfind('/') {
        Some(pos) if pos > 0 => &new_abs[..pos],
        Some(_) => "/", // 根目录
        None => return Err(SysErrNo::EINVAL),
    };
    open(new_parent, OpenFlags::O_RDONLY)?.file()?;

    // TODO: 实现实际的 link 操作（硬链接），这里只是做了路径和存在性检查
    todo!("[sys_linkat] link operation not implemented, checked paths ok");
