pub fn sys_pipe2(pipe: *mut u32, flags: u32) -> SyscallRet {
    let flags = Pipe2Flags::from_bits_truncate(flags);
    trace!(
        "[sys_pipe2] called with pipe=0x{:x} (output pointer for fd array), flags={:?} (bits={:#x})",
        pipe as usize,
        flags,
        flags.bits()
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();

    let read_fd = inner.alloc_fd();
    let (pipe_read, pipe_write) = make_pipe();
    inner
        .fd_table
        .set(read_fd, FileDescriptor::default(FileClass::Abs(pipe_read)));

    let write_fd = inner.alloc_fd();
    inner.fd_table.set(
        write_fd,
        FileDescriptor::default(FileClass::Abs(pipe_write)),
    );
    drop(inner);
    drop(task);
    put_data(token, pipe, read_fd as u32);
    put_data(token, unsafe { pipe.add(1) }, write_fd as u32);
    debug!(
        "[sys_pipe2] created pipe with read_fd={}, write_fd={}",
        read_fd, write_fd
    );
    Ok(0)
}

pub fn sys_getdents64(fd: usize, buf: *mut u8, len: usize) -> SyscallRet {
    trace!(
        "[sys_getdents64] called with fd={}, buf=0x{:x}, len={}",
        fd,
        buf as usize,
        len
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    let mut buffer = UserBuffer::new(translated_byte_buffer(&token, buf, len));
    if fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let filedesc = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    drop(inner);
    drop(task);
    let file = filedesc.file()?;
    if !file.readable() {
        return Err(SysErrNo::EBADF);
    }
    if !file.is_dir() {
        return Err(SysErrNo::ENOTDIR);
    }
    if buf.is_null() || len == 0 {
        return Err(SysErrNo::EINVAL);
    }
    let off = file.lseek(0, SEEK_CUR)?;
    let (de, off) = file
        .inode
        .read_dentry(off, len)
        .map_err(|_| SysErrNo::EIO)?;
    buffer.write(de.as_slice());
    if off == -1 {
        return Ok(0);
    }
    file.lseek(off, SEEK_SET);
    Ok(de.len())
}

