    let file = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    drop(inner);
    drop(task);
    let file = file.file()?;
    let result = file.lseek(offset, whence)?;
    debug!("[sys_lseek] new file position: {}", result);
    Ok(result)
}

