pub fn sys_readv(fd: usize, iov: *const u8, iovcnt: usize) -> SyscallRet {
    if fd >= 3 {
        trace!(
            "[sys_readv] called with fd={}, iov=0x{:x}, iovcnt={}",
            fd,
            iov as usize,
            iovcnt
        );
    }
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let filedesc = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    drop(inner);
    drop(task);
    let file = filedesc.any();
    if !file.readable() {
        return Err(SysErrNo::EBADF);
    }
    let mut ret = 0;
    for i in 0..iovcnt {
        let iov_ptr = unsafe { iov.add(i * core::mem::size_of::<Iovec>()) };
        let iov = unsafe { &*(iov_ptr as *const Iovec) };
        let user_buf = UserBuffer::new(translated_byte_buffer(&token, iov.iov_base, iov.iov_len));
        let read_bytes = file.read(user_buf);
        ret += read_bytes;
    }
    Ok(ret)
}

