    // 恢复原来的偏移量
    file.lseek(current_offset as isize, SEEK_SET)?;

    Ok(bytes_read)
}

pub fn sys_pselect6(
    nfds: usize,
    readfds: *const u8,
    writefds: *const u8,
    exceptfds: *const u8,
    timeout: *const u8,
    sigmask: *const u8,
) -> SyscallRet {
    trace!(
        "[sys_pselect6] called with nfds={}, readfds=0x{:x}, writefds=0x{:x}, exceptfds=0x{:x}, timeout=0x{:x}, sigmask=0x{:x}",
        nfds,
        readfds as usize,
        writefds as usize,
        exceptfds as usize,
        timeout as usize,
        sigmask as usize
    );
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    let token = current_user_token();

    // debug!("[sys_pselect6] nfds is {}, readfds is {}, writefds is {}, exceptfds is {}, timeout is {}, sigmask is {}",nfds,readfds,writefds,exceptfds,timeout,sigmask);

    let old_mask = inner.signal_mask;
    if sigmask as usize != 0 {
        inner.signal_mask = get_data(token, sigmask as *const SignalFlags);
    }

    let nfds = min(nfds, inner.fd_table.get_soft_limit());
    drop(inner);
    drop(task);
    let mut using_readfds = if readfds as usize != 0 {
        Some(get_data(token, readfds as *mut FdSet))
    } else {
        None
    };
    let mut using_writefds = if writefds as usize != 0 {
        Some(get_data(token, writefds as *mut FdSet))
    } else {
        None
    };
    let mut using_exceptfds = if exceptfds as usize != 0 {
        Some(get_data(token, exceptfds as *mut FdSet))
    } else {
        None
    };

    // pselect 不会更新 timeout 的值，而 select 会
    let waittime = if timeout as usize == 0 {
        //为0则永远等待直到完成
        -1
    } else {
        // let timespec = translated_ref(token, timeout as *const Timespec);
        let timespec = get_data(token, timeout as *const Timespec);
        // debug!(
        //     "[sys_pselect6] waittime is {} sec, {} nsec",
        //     timespec.tv_sec, timespec.tv_nsec
        // );

        (timespec.tv_sec * 1_000_000_000 + timespec.tv_nsec) as isize
    };

    let begin = get_time_ms() * 1_000_000;

    //由于每次循环结束需要让出cpu，因此需要在每次循环时重新获得锁
    trace!(
        "[sys_pselect6] entering main loop with waittime: {}",
        waittime
    );
    loop {
        trace!("[sys_pselect6] into loop, waiting for events");
        let task = current_task().unwrap();
        let mut inner = task.inner_exclusive_access();
        let mut num = 0;

        // 如果设置了监视是否可读的 fd
        if let Some(readfds) = using_readfds.as_mut() {
            for i in 0..nfds {
                if readfds.got_fd(i) {
                    if let Some(file) = &inner.fd_table.get_file(i) {
                        let file: Arc<dyn File> = file.any();
                        let event = file.poll(PollEvents::POLLIN);
                        if !event.contains(PollEvents::POLLIN) {
                            readfds.mark_fd(i, false);
                        }
                        num += 1;
                    } else {
                        readfds.mark_fd(i, false);
                    }
                }
            }
        }
        // 如果设置了监视是否可写的 fd
        if let Some(writefds) = using_writefds.as_mut() {
            for i in 0..nfds {
                if writefds.got_fd(i) {
                    if let Some(file) = &inner.fd_table.get_file(i) {
                        let file: Arc<dyn File> = file.any();
                        let event = file.poll(PollEvents::POLLOUT);
                        if !event.contains(PollEvents::POLLOUT) {
                            writefds.mark_fd(i, false);
                        }
                        num += 1;
                    } else {
                        writefds.mark_fd(i, false);
                    }
                }
            }
        }

        // 如果设置了监视异常的 fd
        if let Some(exceptfds) = using_exceptfds.as_mut() {
            for i in 0..nfds {
                if exceptfds.got_fd(i) {
                    if let Some(file) = &inner.fd_table.get_file(i) {
                        let file: Arc<dyn File> = file.any();
                        let event = file.poll(PollEvents::POLLERR | PollEvents::POLLHUP);
                        if !event.contains(PollEvents::POLLERR)
                            && !event.contains(PollEvents::POLLHUP)
                        {
                            exceptfds.mark_fd(i, false);
                        }
                        num += 1;
                    } else {
                        exceptfds.mark_fd(i, false);
                    }
                }
            }
        }

        //如果有响应了则返回,或者如果时间是0，0（只监视一遍），也需要返回结果
        if num > 0 || waittime == 0 {
            // debug!("[sys_pselect6] ret for num:{},waittime:{}", num, waittime);
            if let Some(using_readfds) = using_readfds {
                put_data(token, readfds as *mut FdSet, using_readfds);
            }
            if let Some(using_writefds) = using_writefds {
                put_data(token, writefds as *mut FdSet, using_writefds);
            }
            if let Some(using_exceptfds) = using_exceptfds {
                // debug!("[sys_pselect6] exceptfds is {:?}", using_exceptfds);
                put_data(token, exceptfds as *mut FdSet, using_exceptfds);
            }
            if sigmask as usize != 0 {
                inner.signal_mask = old_mask;
            }
            return Ok(num);
        }

        //或者时间到了也可以返回
        if waittime > 0 && get_time_ms() * 1000000 - begin >= waittime as usize {
            // debug!("[sys_pselect6] ret for timeout");
            if sigmask as usize != 0 {
                inner.signal_mask = old_mask;
            }
            return Ok(0);
        }
        drop(inner);
        drop(task);
        suspend_current_and_run_next();
    }
}

pub fn sys_ppoll(fds: usize, nfds: usize, tmo_p: usize, sigmask: usize) -> SyscallRet {
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    if fds == 0 {
        return Err(SysErrNo::EINVAL);
    }
    let mut fdsv = Vec::new();
    let ptr = fds as *mut PollFd;
    for i in 0..nfds {
        fdsv.push(translated_refmut(
            token,
            (unsafe { ptr.add(i) } as *mut PollFd),
        ));
    }
    let waittime = if tmo_p == 0 {
        -1
    } else {
        let timespec = get_data(token, tmo_p as *const Timespec);
        (timespec.tv_sec * 1_000_000_000 + timespec.tv_nsec) as isize
    };
    let begin = get_time_ms() * 1_000_000;

    drop(inner);
    drop(task);

    loop {
        let task = current_task().unwrap();
        let inner = task.inner_exclusive_access();
        let mut cnt = 0;
        for fd in fdsv.iter_mut() {
            if fd.fd < 0 {
                fd.revents = PollEvents::empty();
                continue;
            }
            if let Some(file) = inner.fd_table.get_file(fd.fd as usize) {
                let revents = file.any().poll(fd.events);
                if revents != PollEvents::empty() {
                    fd.revents = revents;
                    cnt += 1;
                } else {
                    fd.revents = PollEvents::empty();
                }
            } else {
                fd.revents = PollEvents::empty();
            }
        }
        if cnt > 0 {
            return Ok(cnt);
        }
        if waittime >= 0 && (get_time_ms() * 1_000_000 - begin) as isize >= waittime {
            debug!("[sys_ppoll] timeout reached");
            return Ok(0);
        }
        drop(inner);
        drop(task);
        suspend_current_and_run_next();
    }
}

pub fn sys_splice(
    fd_in: usize,
    off_in: *mut u8,
    fd_out: usize,
    off_out: *mut u8,
    len: usize,
    _flags: u32,
) -> SyscallRet {
    trace!(
        "[sys_splice] called with fd_in={}, off_in=0x{:x}, fd_out={}, off_out=0x{:x}, len={}",
        fd_in,
        off_in as usize,
        fd_out,
        off_out as usize,
        len,
    );

    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();

    // 参数检查
    if fd_in >= inner.fd_table.len() || fd_out >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }

    let mut buf = vec![0u8; len];
    let mut inbufv = Vec::new();
    unsafe {
        inbufv.push(core::slice::from_raw_parts_mut(
            buf.as_mut_slice().as_mut_ptr(),
            buf.as_slice().len(),
        ));
    }
    let inbuffer = UserBuffer::new(inbufv);
    if let Ok(file_in) = inner.fd_table.get_file(fd_in).unwrap().file() {
        if let Ok(file_out) = inner.fd_table.get_file(fd_out).unwrap().file() {
            return Err(SysErrNo::EINVAL);
        }
        let file_out = inner.fd_table.get_file(fd_out).unwrap().abs()?;
        if !file_in.readable() || !file_out.writable() {
            return Err(SysErrNo::EBADF);
        }
        if off_in as usize == 0 || off_out as usize != 0 {
            return Err(SysErrNo::EINVAL);
        }
        drop(inner);
        drop(task);
        splice_to_pipe(file_out, file_in, off_in as *const isize, len)
    } else if let Ok(file_in) = inner.fd_table.get_file(fd_in).unwrap().abs() {
        if let Ok(file_out) = inner.fd_table.get_file(fd_out).unwrap().abs() {
            return Err(SysErrNo::EINVAL);
        }
        let file_out = inner.fd_table.get_file(fd_out).unwrap().file()?;
        if !file_in.readable() || !file_out.writable() {
            return Err(SysErrNo::EBADF);
        }
        if off_in as usize != 0 || off_out as usize == 0 {
            return Err(SysErrNo::EINVAL);
        }
        drop(inner);
        drop(task);
        splice_from_pipe(file_in, file_out, off_out as *const isize, len)
    } else {
        Err(SysErrNo::EBADF)
    }
}

pub fn sys_readlinkat(dirfd: isize, path: *const u8, buf: *mut u8, bufsize: usize) -> SyscallRet {
    trace!(
        "[sys_readlinkat] called with dirfd={}, path=0x{:x}, buf=0x{:x} (output pointer for link content), bufsize={}",
        dirfd,
        path as usize,
        buf as usize,
        bufsize
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let path_str = translated_str(token, path);
    debug!("[sys_readlinkat] path string: {}", path_str);
    if path_str == "/proc/self/exe" {
        let size = inner.fsinfo.get_exe().len();
        let mut buffer = UserBuffer::new(translated_byte_buffer(&token, buf, bufsize));
        let res = buffer.write(inner.fsinfo.get_exe().as_bytes());
        return Ok(res);
    }
    let abs_path = inner.get_abs_path(dirfd, &path_str)?;
    drop(inner);
    drop(task);
    let mut linkbuf = vec![0; bufsize];
    debug!("[sys_readlinkat] absolute path: {}", abs_path);
    let file = open(&abs_path, OpenFlags::O_RDONLY)?.file()?;
    let readcnt = file.inode.read_link(&mut linkbuf, bufsize)?;
    let mut buffer = UserBuffer::new(translated_byte_buffer(&token, buf, bufsize));
    buffer.write(&linkbuf);
    Ok(readcnt)
    // TODO: implement symbolic link reading
    // todo!("[sys_readlinkat] symbolic link reading not implemented yet");
}

pub fn sys_fstatat(dirfd: isize, path_ptr: *const u8, kst: *mut u8, flags: usize) -> SyscallRet {
    let flags = FstatatFlags::from_bits(flags as u32).unwrap_or(FstatatFlags::empty());
    trace!(
        "[sys_fstatat] called with dirfd={}, path=0x{:x}, kst=0x{:x},flags:0x{:x} ({:?}) (output pointer for Kstat)",
        dirfd,
        path_ptr as usize,
        kst as usize,
        flags.bits(),
        flags
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let mut kst = UserBuffer::new(translated_byte_buffer(&token, kst, size_of::<Kstat>()));

    let fileclass = if flags.contains(FstatatFlags::AT_EMPTY_PATH) {
        debug!("[sys_fstatat] path is empty, using dirfd as file descriptor");
        // 直接用 dirfd 对应的已打开文件
        let filedesc = inner
            .fd_table
            .get_file(dirfd as usize)
            .ok_or(SysErrNo::EBADF)?;
        FileClass::Abs(filedesc.any())
    } else {
        let path = translated_str(token, path_ptr);
        debug!("[sys_fstatat] path string: {}", path);
        let abs_path = inner.get_abs_path(dirfd, &path)?;
        drop(inner);
        drop(task);
        debug!("[sys_fstatat] absolute path: {}", &abs_path);
        open(&abs_path, OpenFlags::O_RDONLY)?
    };
    let kstat = fileclass.any().fstat();
    kst.write(kstat.as_bytes());
    Ok(0)
}

pub fn sys_fstat(fd: usize, kst: *mut u8) -> SyscallRet {
    trace!(
        "[sys_fstat] called with fd={}, kst=0x{:x} (output pointer for Kstat)",
        fd,
        kst as usize
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    let mut kst = UserBuffer::new(translated_byte_buffer(
        &token,
        kst,
        core::mem::size_of::<Kstat>(),
    ));

    let filedesc = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    drop(inner);
    drop(task);
    let file = filedesc.file()?;
    let kstat = file.fstat();
    kst.write(kstat.as_bytes());
    debug!("[sys_fstat] successfully got file stats for fd {}", fd);
    Ok(0)
}

pub fn sys_fsync(fd: usize) -> SyscallRet {
    trace!("[sys_fsync] called with fd={}", fd);
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let filedesc = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    drop(inner);
    drop(task);
    let file = filedesc.file()?;
    file.inode.sync();
    debug!("[sys_fsync] successfully synced fd {}", fd);
    Ok(0)
}

pub fn sys_utimesat(dirfd: isize, path: *const u8, times: *const u8, flags: u32) -> SyscallRet {
    trace!(
        "[sys_utimesat] called with dirfd={}, path=0x{:x}, times=0x{:x}, flags={:#x}",
        dirfd,
        path as usize,
        times as usize,
        flags
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let path = translated_str(token, path);
    debug!("[sys_utimesat] path string: {}", path);
    let abs_path = inner.get_abs_path(dirfd, &path)?;
    debug!("[sys_utimesat] absolute path: {}", abs_path);
    drop(inner);
    drop(task);
    let now_time = (get_time_ms() / 1000) as u64;

    let (mut atime, mut mtime);
    if times as usize == 0 {
        atime = Some(now_time);
        mtime = Some(now_time);
    } else {
        let atime_spec = get_data(token, times as *const Timespec);
        let mtime_spec = get_data(token, unsafe { (times as *const Timespec).add(1) });
        match atime_spec.tv_nsec {
            UTIME_OMIT => atime = None,
            UTIME_NOW => atime = Some(now_time),
            _ => atime = Some(atime_spec.tv_sec as u64),
        }
        match mtime_spec.tv_nsec {
            UTIME_OMIT => mtime = None,
            UTIME_NOW => mtime = Some(now_time),
            _ => mtime = Some(mtime_spec.tv_sec as u64),
        }
    }

    let osfile = open(&abs_path, OpenFlags::O_RDWR)?.file()?;
    osfile.inode.set_timestamps(atime, mtime, None)?;
    Ok(0)
}

pub fn sys_renameat2(
    olddirfd: isize,
    oldpath: *const u8,
    newdirfd: isize,
    newpath: *const u8,
    flags: u32,
) -> SyscallRet {
    trace!("sys_rename");
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let oldpath = translated_str(token, oldpath);
    let newpath = translated_str(token, newpath);
    debug!("[sys_rename] oldpath:{},newpath:{}", oldpath, newpath);
    let old_abs_path = inner.get_abs_path(olddirfd, &oldpath).unwrap();
    let new_abs_path = inner.get_abs_path(newdirfd, &newpath).unwrap();
    drop(inner);
    drop(task);
    let osfile = open(&old_abs_path, OpenFlags::O_RDWR)?.file()?;
    osfile.inode.rename(&old_abs_path, &new_abs_path)
}

pub fn sys_copy_file_range(
    fd_in: usize,
    off_in: *mut u8,
    fd_out: usize,
    off_out: *mut u8,
    len: usize,
    _flags: u32,
) -> SyscallRet {
    trace!(
        "[sys_copy_file_range] Enter: fd_in={}, off_in=0x{:x}, fd_out={}, off_out=0x{:x}, len={}, flags={}",
        fd_in, off_in as usize, fd_out, off_out as usize, len, _flags
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if len == 0 {
        return Ok(0); // 如果长度为0，直接返回0
    }

    if fd_in >= inner.fd_table.len() || fd_out >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }

    let file_in = inner.fd_table.get_file(fd_in).unwrap().file()?;
    let file_out = inner.fd_table.get_file(fd_out).unwrap().file()?;
    drop(inner);
    drop(task);
    let mut buf = vec![0u8; len];

    if !file_in.readable() || !file_out.writable() {
        return Err(SysErrNo::EBADF);
    }

    //输入缓冲池
    let mut inbufv = Vec::new();
    unsafe {
        inbufv.push(core::slice::from_raw_parts_mut(
            buf.as_mut_slice().as_mut_ptr(),
            buf.as_slice().len(),
        ));
    }
    let inbuffer = UserBuffer::new(inbufv);

    let readcount;
    if off_in as usize == 0 {
        readcount = file_in.read(inbuffer);
    } else {
        let off_in_val = get_data(token, off_in as *const isize);
        if off_in_val < 0 {
            return Err(SysErrNo::EINVAL);
        }
        let cur_offset = file_in.lseek(0, SEEK_CUR)?;
        file_in.lseek(off_in_val, SEEK_SET)?;
        readcount = file_in.read(inbuffer);
        file_in.lseek(cur_offset as isize, SEEK_SET)?;
    }
    info!("read completed, readcount={}", readcount);
    if readcount == 0 {
        return Ok(0); // 如果没有读取到数据，直接返回0
    }

    //输出缓冲池
    let mut outbufv = Vec::new();
    unsafe {
        outbufv.push(core::slice::from_raw_parts_mut(
            buf.as_mut_slice().as_mut_ptr(),
            readcount,
        ));
    }
    let outbuffer = UserBuffer::new(outbufv);

    let writecount;
    if off_out as usize == 0 {
        writecount = file_out.write(outbuffer);
    } else {
        let off_out_val = get_data(token, off_out as *const isize);
        if off_out_val < 0 {
            return Err(SysErrNo::EINVAL);
        }
        let cur_offset = file_out.lseek(0, SEEK_CUR)?;
        file_out.lseek(off_out_val, SEEK_SET)?;
        writecount = file_out.write(outbuffer);
        file_out.lseek(cur_offset as isize, SEEK_SET)?;
    }
    if off_in as usize != 0 {
        let new_offset = get_data(token, off_in as *mut isize) + readcount as isize;
        put_data(token, off_in as *mut isize, new_offset);
    }
    if off_out as usize != 0 {
        let new_offset = get_data(token, off_out as *mut isize) + writecount as isize;
        put_data(token, off_out as *mut isize, new_offset);
    }

    Ok(writecount)
}

pub fn sys_statx(dirfd: isize, path_ptr: *const u8, flags: u32, kst: *mut u8) -> SyscallRet {
    trace!(
        "[sys_statx] called with dirfd={}, path=0x{:x}, flags={:#x}, kst=0x{:x} (output pointer for Kstat)",
        dirfd,
        path_ptr as usize,
        flags,
        kst as usize
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    let path = translated_str(token, path_ptr);
    debug!("[sys_statx] path string: {}", path);
    let mut kst = UserBuffer::new(translated_byte_buffer(
        &token,
        kst,
        core::mem::size_of::<Statx>(),
    ));
    let fileclass = if path_ptr as usize == 0 {
        debug!("[sys_statx] path is empty, using dirfd as file descriptor");
        // 直接用 dirfd 对应的已打开文件
        let filedesc = inner
            .fd_table
            .get_file(dirfd as usize)
            .ok_or(SysErrNo::EBADF)?;
        FileClass::Abs(filedesc.any())
    } else {
        let abs_path = inner.get_abs_path(dirfd, &path)?;
        drop(inner);
        drop(task);
        debug!("[sys_statx] absolute path: {}", &abs_path);
        open(&abs_path, OpenFlags::O_RDONLY)?
    };
    let statx: Statx = fileclass.file()?.fstat().into();
    kst.write(statx.as_bytes());
    Ok(0)
}

fn main() -> i32 {
    if fork() == 0 {
        exec("bin/busybox\0", &["sh\0".as_ptr()]);
    } else {
        loop {
            let mut exit_code: i32 = 0;
            let pid = wait(&mut exit_code);
            if pid == -1 {
                yield_();
                continue;
            }
            println!(
                "[initproc] Released a zombie process, pid={}, exit_code={}",
                pid, exit_code,
            );
        }
    }
    0
}

